    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @GET
    @Path("/{userId}/profile")
    @Produces("application/json")
    public Response getUserProfile(@PathParam("userId") int userId) {
        // VULNERABLE: No authentication check
        // VULNERABLE: No authorization check - any user can access any profile
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT id, name, email, ssn, address, phone FROM users WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, userId);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
