```

**Why This Is Dangerous**:
- No authentication: Anyone can call this endpoint without logging in
- No authorization: Even authenticated users can access ANY user's profile by changing the ID
- Sensitive data exposure: SSN, address, and phone numbers returned without access control
- Sequential IDs make enumeration trivial
- Error messages leak implementation details

**SECURE VERSION**:

```java
import javax.servlet.http.HttpServletRequest;
import javax.ws.rs.*;
import javax.ws.rs.core.Context;
import javax.ws.rs.core.Response;
import javax.annotation.security.RolesAllowed;
import java.sql.*;
import java.util.logging.Logger;

@Path("/api/users")
public class SecureUserProfileController {

    private static final Logger LOGGER = Logger.getLogger(SecureUserProfileController.class.getName());
    private final UserRepository userRepository;
    private final AuthorizationService authService;

    public SecureUserProfileController(UserRepository userRepository, AuthorizationService authService) {
        this.userRepository = userRepository;
        this.authService = authService;
    }

    @GET
    @Path("/{userId}/profile")
    @Produces("application/json")
    @RolesAllowed({"USER", "ADMIN"})
    public Response getUserProfile(
            @PathParam("userId") String userIdParam,
            @Context HttpServletRequest request) {

        // SECURITY CONTROL 1: Get authenticated user from security context
        String authenticatedUserId = authService.getAuthenticatedUserId(request);
        if (authenticatedUserId == null) {
            LOGGER.warning("Unauthenticated access attempt to profile endpoint");
            return Response.status(401).entity("Authentication required").build();
        }

        // SECURITY CONTROL 2: Validate and parse the user ID
        int targetUserId;
        try {
            targetUserId = Integer.parseInt(userIdParam);
            if (targetUserId <= 0) {
                throw new NumberFormatException();
            }
        } catch (NumberFormatException e) {
            return Response.status(400).entity("Invalid user ID format").build();
        }

        // SECURITY CONTROL 3: Authorization check - users can only access their own profile
        boolean isAdmin = authService.hasRole(authenticatedUserId, "ADMIN");
        boolean isOwnProfile = authenticatedUserId.equals(String.valueOf(targetUserId));

        if (!isOwnProfile && !isAdmin) {
            LOGGER.warning(String.format(
                "Authorization failure: User %s attempted to access profile of user %d",
                authenticatedUserId, targetUserId));
            // Return 404 instead of 403 to prevent enumeration
            return Response.status(404).entity("Resource not found").build();
        }

        // SECURITY CONTROL 4: Fetch with appropriate data masking
        try {
            UserProfile profile = userRepository.findById(targetUserId);
            if (profile == null) {
                return Response.status(404).entity("Resource not found").build();
            }

            // Mask sensitive data for non-admin users
            if (!isAdmin) {
                profile = profile.withMaskedSensitiveData();
            }

            LOGGER.info(String.format("Profile access: User %s accessed profile %d",
                authenticatedUserId, targetUserId));

            return Response.ok(profile).build();

        } catch (Exception e) {
            LOGGER.severe("Database error during profile fetch: " + e.getMessage());
            return Response.serverError().entity("An error occurred").build();
        }
    }
}
```

**Key Security Controls**:
- **Authentication enforcement**: @RolesAllowed annotation plus explicit check ensures only authenticated users can access the endpoint
- **Authorization verification**: Explicit check that the requesting user owns the resource OR has admin privileges
- **Uniform error responses**: Returns 404 for both "not found" and "not authorized" to prevent user enumeration
- **Data masking**: Sensitive fields like SSN are masked for non-admin access
- **Audit logging**: All access attempts are logged for security monitoring

Hierarchical and relationship-based authorization requires a more sophisticated approach. Let me show you a production-ready pattern using Attribute-Based Access Control (ABAC) combined with policy enforcement points.

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.HttpServletRequest;
import javax.ws.rs.*;
import javax.ws.rs.core.Context;
import javax.ws.rs.core.Response;
import javax.inject.Inject;
import java.util.logging.Logger;
import java.util.Set;
import java.util.UUID;

@Path("/api/projects")
public class ProjectResourceController {

    private static final Logger AUDIT_LOG = Logger.getLogger("SECURITY_AUDIT");
    private static final Logger APP_LOG = Logger.getLogger(ProjectResourceController.class.getName());

    @Inject
    private AuthenticationService authService;

    @Inject
    private AuthorizationPolicyEngine policyEngine;

    @Inject
    private ProjectRepository projectRepository;

    @Inject
    private RateLimiter rateLimiter;

    @GET
    @Path("/{projectId}")
    @Produces("application/json")
    public Response getProject(
            @PathParam("projectId") String projectIdParam,
            @Context HttpServletRequest request) {

        String requestId = UUID.randomUUID().toString();
        long startTime = System.currentTimeMillis();

        try {
            // LAYER 1: Authentication
            AuthenticatedUser currentUser = authService.authenticate(request);
            if (currentUser == null) {
                auditLog(requestId, "AUTHN_FAILURE", null, projectIdParam, "No valid session");
                return unauthorizedResponse();
            }

            // LAYER 2: Rate Limiting
            if (!rateLimiter.allowRequest(currentUser.getId(), "project_access")) {
                auditLog(requestId, "RATE_LIMITED", currentUser.getId(), projectIdParam, "Exceeded rate limit");
                return Response.status(429)
                    .header("Retry-After", "60")
                    .entity("Too many requests")
                    .build();
            }

            // LAYER 3: Input Validation
            UUID projectId = validateAndParseUUID(projectIdParam);
            if (projectId == null) {
                return Response.status(400).entity("Invalid project identifier").build();
            }

            // LAYER 4: Resource Existence Check (before authorization to prevent timing attacks)
            Project project = projectRepository.findById(projectId);
            if (project == null) {
                auditLog(requestId, "RESOURCE_NOT_FOUND", currentUser.getId(), projectIdParam, "Project not found");
                return notFoundResponse();
            }

            // LAYER 5: Authorization Policy Evaluation
            AuthorizationContext authzContext = AuthorizationContext.builder()
                .subject(currentUser)
                .resource(project)
                .action("READ")
                .environment(buildEnvironmentContext(request))
                .build();

            AuthorizationDecision decision = policyEngine.evaluate(authzContext);

            if (!decision.isPermitted()) {
                auditLog(requestId, "AUTHZ_DENIED", currentUser.getId(), projectIdParam, 
                    decision.getDenialReason());
                // Return 404 to prevent enumeration
                return notFoundResponse();
            }

            // LAYER 6: Field-Level Access Control
            ProjectDTO responseDto = applyFieldLevelPermissions(project, currentUser, decision);

            auditLog(requestId, "ACCESS_GRANTED", currentUser.getId(), projectIdParam, 
                "Fields visible: " + responseDto.getVisibleFields());

            return Response.ok(responseDto)
                .header("X-Request-Id", requestId)
                .build();

        } catch (Exception e) {
            APP_LOG.severe("Unexpected error processing request " + requestId + ": " + e.getMessage());
            return Response.serverError().entity("Internal error").build();
        } finally {
            long duration = System.currentTimeMillis() - startTime;
            APP_LOG.info(String.format("Request %s completed in %dms", requestId, duration));
        }
    }

    private UUID validateAndParseUUID(String input) {
        if (input == null || input.length() != 36) {
            return null;
        }
        try {
            return UUID.fromString(input);
        } catch (IllegalArgumentException e) {
            return null;
        }
    }

    private EnvironmentContext buildEnvironmentContext(HttpServletRequest request) {
        return EnvironmentContext.builder()
            .clientIp(getClientIp(request))
            .userAgent(request.getHeader("User-Agent"))
            .requestTime(System.currentTimeMillis())
            .isInternalNetwork(isInternalIp(getClientIp(request)))
            .build();
    }

    private ProjectDTO applyFieldLevelPermissions(
            Project project, 
            AuthenticatedUser user, 
            AuthorizationDecision decision) {

        ProjectDTO.Builder builder = ProjectDTO.builder()
            .id(project.getId())
            .name(project.getName())
            .description(project.getDescription());

        // Only project owners and admins see financial data
        if (decision.hasPermission("VIEW_FINANCIALS")) {
            builder.budget(project.getBudget());
            builder.costs(project.getCosts());
        }

        // Only team leads and above see member details
        if (decision.hasPermission("VIEW_MEMBERS")) {
            builder.teamMembers(project.getTeamMembers());
        }

        // Sensitive notes only visible to owners
        if (decision.hasPermission("VIEW_SENSITIVE")) {
            builder.internalNotes(project.getInternalNotes());
        }

        return builder.build();
    }

    private Response unauthorizedResponse() {
        return Response.status(401)
            .header("WWW-Authenticate", "Bearer realm=\"api\"")
            .entity("Authentication required")
            .build();
    }

    private Response notFoundResponse() {
        return Response.status(404).entity("Resource not found").build();
    }

    private void auditLog(String requestId, String event, String userId, 
                          String resourceId, String details) {
        AUDIT_LOG.info(String.format(
            "REQUEST_ID=%s EVENT=%s USER=%s RESOURCE=%s DETAILS=%s",
            requestId, event, userId != null ? userId : "anonymous", 
            resourceId, details));
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private boolean isInternalIp(String ip) {
        return ip.startsWith("10.") || ip.startsWith("192.168.") || 
               ip.startsWith("172.16.") || ip.equals("127.0.0.1");
    }
}
```

**Authorization Policy Engine**:

```java
import java.util.*;

public class AuthorizationPolicyEngine {

    private final MembershipRepository membershipRepository;
    private final TeamHierarchyService hierarchyService;

    public AuthorizationPolicyEngine(MembershipRepository membershipRepository,
                                     TeamHierarchyService hierarchyService) {
        this.membershipRepository = membershipRepository;
        this.hierarchyService = hierarchyService;
    }

    public AuthorizationDecision evaluate(AuthorizationContext context) {
        AuthenticatedUser subject = context.getSubject();
        Project resource = (Project) context.getResource();
        String action = context.getAction();

        Set<String> grantedPermissions = new HashSet<>();

        // POLICY 1: System administrators have full access
        if (subject.hasRole("SYSTEM_ADMIN")) {
            grantedPermissions.addAll(Arrays.asList(
                "VIEW_FINANCIALS", "VIEW_MEMBERS", "VIEW_SENSITIVE"));
            return AuthorizationDecision.permit(grantedPermissions);
        }

        // POLICY 2: Project owners have full access to their projects
        if (resource.getOwnerId().equals(subject.getId())) {
            grantedPermissions.addAll(Arrays.asList(
                "VIEW_FINANCIALS", "VIEW_MEMBERS", "VIEW_SENSITIVE"));
            return AuthorizationDecision.permit(grantedPermissions);
        }

        // POLICY 3: Check direct project membership
        Optional<ProjectMembership> membership = membershipRepository
            .findMembership(subject.getId(), resource.getId());

        if (membership.isPresent()) {
            ProjectRole role = membership.get().getRole();

            switch (role) {
                case PROJECT_MANAGER:
                    grantedPermissions.addAll(Arrays.asList(
                        "VIEW_FINANCIALS", "VIEW_MEMBERS"));
                    break;
                case TEAM_LEAD:
                    grantedPermissions.add("VIEW_MEMBERS");
                    break;
                case CONTRIBUTOR:
                    // Basic read access only, no special permissions
                    break;
            }
            return AuthorizationDecision.permit(grantedPermissions);
        }

        // POLICY 4: Check organizational hierarchy access
        // Users can view projects in their team or child teams
        if (hierarchyService.isInUserHierarchy(subject.getId(), resource.getTeamId())) {
            // Hierarchical access grants read-only, no sensitive fields
            return AuthorizationDecision.permit(grantedPermissions);
        }

        // POLICY 5: Check if project is public within organization
        if (resource.getVisibility() == Visibility.ORGANIZATION_PUBLIC &&
            subject.getOrganizationId().equals(resource.getOrganizationId())) {
            return AuthorizationDecision.permit(grantedPermissions);
        }

        // Default: Deny access
        return AuthorizationDecision.deny("No matching authorization policy");
    }
}
```

**Defense in Depth Layers**:

1. **Authentication Layer**: Validates JWT/session and extracts user identity before any business logic
```java
AuthenticatedUser currentUser = authService.authenticate(request);
if (currentUser == null) {
    return unauthorizedResponse();
}
```

2. **Rate Limiting Layer**: Prevents enumeration attacks and DoS
```java
if (!rateLimiter.allowRequest(currentUser.getId(), "project_access")) {
    return Response.status(429).header("Retry-After", "60").build();
}
```

3. **Policy-Based Authorization Layer**: Separates authorization logic from business logic for maintainability and auditability
```java
AuthorizationDecision decision = policyEngine.evaluate(authzContext);
if (!decision.isPermitted()) {
    return notFoundResponse(); // Prevents enumeration
}
```

**Additional Protections**:
- **UUID identifiers**: Use UUIDs instead of sequential integers to prevent enumeration attacks
- **Consistent timing**: Resource existence check before authorization to prevent timing-based user enumeration
- **Field-level permissions**: Different users see different fields based on their authorization level
- **Comprehensive audit logging**: Every access attempt is logged with request ID, user, resource, and outcome
- **Environment context**: Authorization can consider IP address, time of day, and network location for additional security
- **Separation of concerns**: Authorization policies are centralized and can be modified without changing controllers

Excellent question. Complex authorization requires a structured approach - Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC). Here's a production-ready pattern used in enterprise Go applications.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"time"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

// Permission constants
const (
	PermissionRead       = "read"
	PermissionWrite      = "write"
	PermissionDelete     = "delete"
	PermissionAdmin      = "admin"
	PermissionViewPII    = "view_pii"
	PermissionExportData = "export_data"
)

// Resource types
const (
	ResourceUser    = "user"
	ResourceTeam    = "team"
	ResourceProject = "project"
)

type contextKey string

const userContextKey contextKey = "authenticatedUser"

// AuthenticatedUser with role and team information
type AuthenticatedUser struct {
	ID          int
	Email       string
	Roles       []string
	TeamIDs     []int
	Permissions map[string][]string // resource_type -> permissions
}

// AuthorizationService handles all permission checks
type AuthorizationService struct {
	db     *sql.DB
	logger *log.Logger
}

// AuthzDecision records the authorization decision for audit
type AuthzDecision struct {
	UserID       int
	ResourceType string
	ResourceID   int
	Action       string
	Allowed      bool
	Reason       string
	Timestamp    time.Time
}

// CheckAccess implements centralized authorization logic
func (as *AuthorizationService) CheckAccess(
	ctx context.Context,
	user *AuthenticatedUser,
	resourceType string,
	resourceID int,
	requiredPermission string,
) (bool, string) {

	// Layer 1: Check if user has global admin role
	for _, role := range user.Roles {
		if role == "super_admin" {
			as.logDecision(user.ID, resourceType, resourceID, requiredPermission, true, "super_admin_role")
			return true, "super_admin_role"
		}
	}

	// Layer 2: Check resource-specific permissions from user's permission map
	if perms, ok := user.Permissions[resourceType]; ok {
		for _, p := range perms {
			if p == requiredPermission || p == PermissionAdmin {
				as.logDecision(user.ID, resourceType, resourceID, requiredPermission, true, "direct_permission")
				return true, "direct_permission"
			}
		}
	}

	// Layer 3: Check ownership (user accessing their own resource)
	if resourceType == ResourceUser && resourceID == user.ID {
		if requiredPermission == PermissionRead || requiredPermission == PermissionWrite {
			as.logDecision(user.ID, resourceType, resourceID, requiredPermission, true, "owner_access")
			return true, "owner_access"
		}
	}

	// Layer 4: Check team-based access from database
	if as.checkTeamAccess(ctx, user, resourceType, resourceID, requiredPermission) {
		as.logDecision(user.ID, resourceType, resourceID, requiredPermission, true, "team_access")
		return true, "team_access"
	}

	// Default deny
	as.logDecision(user.ID, resourceType, resourceID, requiredPermission, false, "no_matching_permission")
	return false, "no_matching_permission"
}

// checkTeamAccess verifies team-based permissions in database
func (as *AuthorizationService) checkTeamAccess(
	ctx context.Context,
	user *AuthenticatedUser,
	resourceType string,
	resourceID int,
	requiredPermission string,
) bool {
	if len(user.TeamIDs) == 0 {
		return false
	}

	// Query checks if any of user's teams has access to this resource
	query := `
		SELECT EXISTS(
			SELECT 1 FROM team_resource_permissions trp
			WHERE trp.team_id = ANY($1)
			AND trp.resource_type = $2
			AND trp.resource_id = $3
			AND $4 = ANY(trp.permissions)
		)
	`

	var hasAccess bool
	err := as.db.QueryRowContext(ctx, query,
		user.TeamIDs, resourceType, resourceID, requiredPermission,
	).Scan(&hasAccess)

	if err != nil {
		as.logger.Printf("ERROR: Team access check failed: %v", err)
		return false // Fail closed
	}

	return hasAccess
}

// logDecision creates audit trail for all authorization decisions
func (as *AuthorizationService) logDecision(
	userID int,
	resourceType string,
	resourceID int,
	action string,
	allowed bool,
	reason string,
) {
	decision := AuthzDecision{
		UserID:       userID,
		ResourceType: resourceType,
		ResourceID:   resourceID,
		Action:       action,
		Allowed:      allowed,
		Reason:       reason,
		Timestamp:    time.Now().UTC(),
	}

	// Log to structured logging for SIEM integration
	if !allowed {
		as.logger.Printf("SECURITY_ALERT: Authorization denied - user=%d resource=%s/%d action=%s reason=%s",
			userID, resourceType, resourceID, action, reason)
	}

	// Async write to audit table (non-blocking)
	go func() {
		_, err := as.db.Exec(`
			INSERT INTO authorization_audit_log 
			(user_id, resource_type, resource_id, action, allowed, reason, created_at)
			VALUES ($1, $2, $3, $4, $5, $6, $7)`,
			decision.UserID, decision.ResourceType, decision.ResourceID,
			decision.Action, decision.Allowed, decision.Reason, decision.Timestamp,
		)
		if err != nil {
			as.logger.Printf("ERROR: Failed to write audit log: %v", err)
		}
	}()
}

// RequirePermission middleware generator for route-level authorization
func RequirePermission(
	authzService *AuthorizationService,
	resourceType string,
	permission string,
	resourceIDParam string,
) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			user, ok := r.Context().Value(userContextKey).(*AuthenticatedUser)
			if !ok || user == nil {
				http.Error(w, "Unauthorized", http.StatusUnauthorized)
				return
			}

			// Extract resource ID from URL
			vars := mux.Vars(r)
			resourceID, err := strconv.Atoi(vars[resourceIDParam])
			if err != nil {
				http.Error(w, "Invalid resource ID", http.StatusBadRequest)
				return
			}

			// Check authorization
			allowed, reason := authzService.CheckAccess(
				r.Context(), user, resourceType, resourceID, permission,
			)

			if !allowed {
				// Return 403 Forbidden, not 404 (don't leak resource existence)
				w.Header().Set("X-Authorization-Reason", reason) // Debug header (remove in prod)
				http.Error(w, "Forbidden", http.StatusForbidden)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// Example protected handler
func GetUserProfile(w http.ResponseWriter, r *http.Request) {
	// Authorization already verified by middleware
	vars := mux.Vars(r)
	userID, _ := strconv.Atoi(vars["id"])

	// Fetch and return user data...
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"id":      userID,
		"message": "Profile data would be here",
	})
}

func main() {
	logger := log.Default()
	db, _ := sql.Open("postgres", "postgres://localhost/myapp?sslmode=disable")

	authzService := &AuthorizationService{db: db, logger: logger}

	router := mux.NewRouter()

	// Apply authorization middleware to protected routes
	userRouter := router.PathPrefix("/api/users").Subrouter()
	userRouter.Use(RequirePermission(authzService, ResourceUser, PermissionRead, "id"))
	userRouter.HandleFunc("/{id}", GetUserProfile).Methods("GET")

	fmt.Println("Server starting on :8080")
	http.ListenAndServe(":8080", router)
}
```

**Defense in Depth Layers**:

1. **Centralized Authorization Service**: All permission checks go through one service, ensuring consistent enforcement
```go
allowed, reason := authzService.CheckAccess(ctx, user, resourceType, resourceID, permission)
```

2. **Multiple Permission Sources**: Checks roles, direct permissions, ownership, AND team-based access
```go
// Layer 1: Global admin role
// Layer 2: Resource-specific permissions
// Layer 3: Resource ownership
// Layer 4: Team-based database lookup
```

3. **Middleware-based Enforcement**: Authorization happens before handler code executes
```go
userRouter.Use(RequirePermission(authzService, ResourceUser, PermissionRead, "id"))
```

**Additional Protections**:

- **Audit logging for all decisions**: Both allowed and denied requests are logged with reasons, enabling security monitoring and incident investigation
- **Fail-closed design**: Any error in permission checking results in denial - never fail open
- **Consistent HTTP responses**: Returns 403 Forbidden (not 404) to prevent information disclosure about resource existence
- **Structured logging**: Uses format compatible with SIEM systems for automated alerting on suspicious patterns like bulk 403 responses
- **Team permission caching**: For high-traffic scenarios, add Redis cache layer to reduce database load while maintaining security
- **Permission inheritance**: Can easily extend to support hierarchical permissions (org -> team -> project -> resource)

