    $fields = ['id', 'name', 'email', 'address', 'phone', 'balance', 'created_at'];

    // Only include sensitive fields if user has permission
    if ($auth->hasPermission(AuthorizationService::PERM_VIEW_SENSITIVE_DATA)) {
        $fields[] = 'ssn_masked';
        $fields[] = 'date_of_birth';
    }

    $fieldList = implode(', ', $fields);
    $stmt = $pdo->prepare("SELECT {$fieldList} FROM accounts WHERE id = ?");
    $stmt->execute([$accountId]);
    $account = $stmt->fetch(PDO::FETCH_ASSOC);

    if ($account) {
        // LAYER 7: Audit successful access
        $audit->log('account_viewed', $auth->getCurrentUserId(), [
            'target_account' => $accountId,
            'fields_accessed' => $fields,
            'accessor_role' => $auth->getCurrentUserRole()
        ]);

        echo json_encode(['data' => $account]);
    } else {
        http_response_code(404);
        echo json_encode(['error' => 'Account not found']);
    }

} catch (PDOException $e) {
    error_log("Database error in get_account: " . $e->getMessage());
    $audit->log('database_error', $auth->getCurrentUserId(), ['endpoint' => 'get_account']);
