**Why This Is Dangerous**:
- No [Authorize] attribute means endpoints may be accessible without authentication
- No ownership verification - any user can access any other user's data by changing the ID
- Exposes sensitive PII (SSN, address) without role-based access control
- Bulk data endpoint allows mass harvesting of user information
- This is the exact vulnerability pattern that exposed 38 million records in Power Apps

**SECURE VERSION**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using System.Security.Claims;
using System.Threading.Tasks;
using MyApp.Data;
using MyApp.Models;
using MyApp.Services;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize] // Require authentication for all endpoints
    public class UsersController : ControllerBase
    {
        private readonly ApplicationDbContext _context;
        private readonly IAuthorizationService _authorizationService;
        private readonly ILogger<UsersController> _logger;

        public UsersController(
            ApplicationDbContext context,
            IAuthorizationService authorizationService,
            ILogger<UsersController> logger)
        {
            _context = context;
            _authorizationService = authorizationService;
            _logger = logger;
        }

        [HttpGet("{id}")]
        public async Task<ActionResult<UserDto>> GetUser(int id)
        {
            var currentUserId = GetCurrentUserId();
            var user = await _context.Users.FindAsync(id);

            if (user == null)
            {
                return NotFound();
            }

            // AUTHORIZATION CHECK: User can only access their own data
            // OR must have Admin role for other users
            var authResult = await _authorizationService.AuthorizeAsync(
                User, user, "UserDataAccessPolicy");

            if (!authResult.Succeeded)
            {
                _logger.LogWarning(
                    "Unauthorized access attempt: User {CurrentUser} tried to access User {TargetUser}",
                    currentUserId, id);
                return Forbid();
            }

            // Return appropriate data based on access level
            return CreateUserDto(user, User.IsInRole("Admin"));
        }

        [HttpGet]
        [Authorize(Roles = "Admin")] // Only admins can list all users
        public async Task<ActionResult<List<UserDto>>> GetAllUsers()
        {
            _logger.LogInformation("Admin {UserId} accessed user list", GetCurrentUserId());

            var users = await _context.Users.ToListAsync();
            return users.Select(u => CreateUserDto(u, true)).ToList();
        }

        private int GetCurrentUserId()
        {
            var claim = User.FindFirst(ClaimTypes.NameIdentifier);
            return int.Parse(claim?.Value ?? "0");
        }

        private UserDto CreateUserDto(User user, bool includeFullDetails)
        {
            var dto = new UserDto
            {
                Id = user.Id,
                Email = user.Email,
                FullName = user.FullName
            };

            if (includeFullDetails)
            {
                dto.PhoneNumber = user.PhoneNumber;
                // SSN is masked even for admins in API responses
                dto.SSN = MaskSsn(user.SSN);
            }

            return dto;
        }

        private string MaskSsn(string ssn) => 
            string.IsNullOrEmpty(ssn) ? null : $"***-**-{ssn.Substring(ssn.Length - 4)}";
    }
}
```

**Key Security Controls**:
- **[Authorize] attribute**: Enforces authentication at controller level, all endpoints require valid token
- **Resource-based authorization**: Uses IAuthorizationService with custom policy to verify user ownership
- **Role-based access control**: Admin-only endpoints use [Authorize(Roles = "Admin")]
- **Audit logging**: All access attempts are logged with user context for forensic analysis
- **Data minimization**: Sensitive fields (SSN) are masked even when returned to authorized users

Multi-tenant authorization is where most access control vulnerabilities occur in production systems. You need a comprehensive approach with resource-based policies and tenant isolation.

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System.Security.Claims;
using System.Threading.Tasks;
using MyApp.Authorization;
using MyApp.Data;
using MyApp.Models;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/organizations/{orgId}/users")]
    [Authorize]
    public class OrganizationUsersController : ControllerBase
    {
        private readonly ApplicationDbContext _context;
        private readonly IAuthorizationService _authorizationService;
        private readonly ILogger<OrganizationUsersController> _logger;
        private readonly IAuditService _auditService;

        public OrganizationUsersController(
            ApplicationDbContext context,
            IAuthorizationService authorizationService,
            ILogger<OrganizationUsersController> logger,
            IAuditService auditService)
        {
            _context = context;
            _authorizationService = authorizationService;
            _logger = logger;
            _auditService = auditService;
        }

        [HttpGet("{userId}")]
        public async Task<ActionResult<UserDto>> GetOrganizationUser(
            int orgId, int userId)
        {
            // LAYER 1: Verify organization exists and user has access
            var org = await _context.Organizations
                .Include(o => o.Members)
                .FirstOrDefaultAsync(o => o.Id == orgId);

            if (org == null)
            {
                return NotFound(new { error = "Organization not found" });
            }

            // LAYER 2: Resource-based authorization for organization access
            var orgAuthResult = await _authorizationService.AuthorizeAsync(
                User, org, OrganizationOperations.ViewMembers);

            if (!orgAuthResult.Succeeded)
            {
                await _auditService.LogUnauthorizedAccessAsync(
                    GetCurrentUserId(), "Organization", orgId,
                    "ViewMembers", Request.HttpContext.Connection.RemoteIpAddress?.ToString());
                return Forbid();
            }

            // LAYER 3: Verify target user belongs to the organization
            var targetUser = await _context.Users
                .Include(u => u.OrganizationMemberships)
                .FirstOrDefaultAsync(u => u.Id == userId);

            if (targetUser == null)
            {
                return NotFound(new { error = "User not found" });
            }

            // LAYER 4: Tenant isolation - ensure user is actually in this org
            if (!targetUser.OrganizationMemberships.Any(m => m.OrganizationId == orgId))
            {
                _logger.LogWarning(
                    "Cross-tenant access attempt: User {CurrentUser} in Org {OrgId} tried to access User {TargetUser}",
                    GetCurrentUserId(), orgId, userId);
                return NotFound(new { error = "User not found" }); // Don't reveal existence
            }

            // LAYER 5: Check permission level for sensitive data
            var membership = await GetCurrentUserMembership(orgId);
            var canViewSensitive = membership?.Role == OrgRole.Admin || 
                                   membership?.Role == OrgRole.HR;

            await _auditService.LogDataAccessAsync(
                GetCurrentUserId(), "User", userId, orgId);

            return CreateUserDto(targetUser, canViewSensitive);
        }

        [HttpGet]
        public async Task<ActionResult<PaginatedResult<UserDto>>> GetOrganizationUsers(
            int orgId,
            [FromQuery] int page = 1,
            [FromQuery] int pageSize = 20)
        {
            // Enforce reasonable limits
            pageSize = Math.Min(pageSize, 100);

            var org = await _context.Organizations.FindAsync(orgId);
            if (org == null)
            {
                return NotFound();
            }

            var authResult = await _authorizationService.AuthorizeAsync(
                User, org, OrganizationOperations.ViewMembers);

            if (!authResult.Succeeded)
            {
                return Forbid();
            }

            // Query only users in THIS organization (tenant isolation)
            var query = _context.Users
                .Where(u => u.OrganizationMemberships.Any(m => m.OrganizationId == orgId));

            var totalCount = await query.CountAsync();
            var users = await query
                .OrderBy(u => u.FullName)
                .Skip((page - 1) * pageSize)
                .Take(pageSize)
                .ToListAsync();

            var membership = await GetCurrentUserMembership(orgId);
            var canViewSensitive = membership?.Role == OrgRole.Admin;

            return new PaginatedResult<UserDto>
            {
                Items = users.Select(u => CreateUserDto(u, canViewSensitive)).ToList(),
                TotalCount = totalCount,
                Page = page,
                PageSize = pageSize
            };
        }

        private int GetCurrentUserId()
        {
            var claim = User.FindFirst(ClaimTypes.NameIdentifier);
            if (claim == null || !int.TryParse(claim.Value, out var userId))
            {
                throw new UnauthorizedAccessException("Invalid user identity");
            }
            return userId;
        }

        private async Task<OrganizationMembership> GetCurrentUserMembership(int orgId)
        {
            var userId = GetCurrentUserId();
            return await _context.OrganizationMemberships
                .FirstOrDefaultAsync(m => m.UserId == userId && m.OrganizationId == orgId);
        }

        private UserDto CreateUserDto(User user, bool includeFullDetails)
        {
            return new UserDto
            {
                Id = user.Id,
                Email = user.Email,
                FullName = user.FullName,
                PhoneNumber = includeFullDetails ? user.PhoneNumber : null,
                Department = user.Department
            };
        }
    }
}
```

**Custom Authorization Handler**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Authorization.Infrastructure;
using System.Security.Claims;
using System.Threading.Tasks;
using MyApp.Data;
using MyApp.Models;

namespace MyApp.Authorization
{
    public static class OrganizationOperations
    {
        public static OperationAuthorizationRequirement ViewMembers =
            new OperationAuthorizationRequirement { Name = nameof(ViewMembers) };
        public static OperationAuthorizationRequirement ManageMembers =
            new OperationAuthorizationRequirement { Name = nameof(ManageMembers) };
        public static OperationAuthorizationRequirement ViewSensitiveData =
            new OperationAuthorizationRequirement { Name = nameof(ViewSensitiveData) };
    }

    public class OrganizationAuthorizationHandler :
        AuthorizationHandler<OperationAuthorizationRequirement, Organization>
    {
        private readonly ApplicationDbContext _context;
        private readonly ILogger<OrganizationAuthorizationHandler> _logger;

        public OrganizationAuthorizationHandler(
            ApplicationDbContext context,
            ILogger<OrganizationAuthorizationHandler> logger)
        {
            _context = context;
            _logger = logger;
        }

        protected override async Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            OperationAuthorizationRequirement requirement,
            Organization resource)
        {
            var userIdClaim = context.User.FindFirst(ClaimTypes.NameIdentifier);
            if (userIdClaim == null || !int.TryParse(userIdClaim.Value, out var userId))
            {
                _logger.LogWarning("Authorization check failed: No valid user ID claim");
                return;
            }

            // Check if user is a member of the organization
            var membership = await _context.OrganizationMemberships
                .FirstOrDefaultAsync(m => 
                    m.UserId == userId && 
                    m.OrganizationId == resource.Id &&
                    m.IsActive);

            if (membership == null)
            {
                _logger.LogDebug(
                    "User {UserId} is not a member of Organization {OrgId}",
                    userId, resource.Id);
                return; // Fail the requirement
            }

            // Check permission based on operation and role
            var hasPermission = requirement.Name switch
            {
                nameof(OrganizationOperations.ViewMembers) =>
                    membership.Role >= OrgRole.Member,
                nameof(OrganizationOperations.ManageMembers) =>
                    membership.Role >= OrgRole.Admin,
                nameof(OrganizationOperations.ViewSensitiveData) =>
                    membership.Role == OrgRole.Admin || membership.Role == OrgRole.HR,
                _ => false
            };

            if (hasPermission)
            {
                context.Succeed(requirement);
            }
        }
    }
}
```

**Startup Configuration**:

```csharp
using Microsoft.AspNetCore.Authorization;
using MyApp.Authorization;

public void ConfigureServices(IServiceCollection services)
{
    services.AddAuthorization(options =>
    {
        // Global policy: all endpoints require authentication
        options.FallbackPolicy = new AuthorizationPolicyBuilder()
            .RequireAuthenticatedUser()
            .Build();

        // Organization member policy
        options.AddPolicy("OrgMember", policy =>
            policy.Requirements.Add(new OrganizationMemberRequirement()));
    });

    // Register authorization handlers
    services.AddScoped<IAuthorizationHandler, OrganizationAuthorizationHandler>();
    services.AddScoped<IAuditService, AuditService>();

    // Configure rate limiting
    services.AddRateLimiter(options =>
    {
        options.GlobalLimiter = PartitionedRateLimiter.Create<HttpContext, string>(context =>
            RateLimitPartition.GetFixedWindowLimiter(
                partitionKey: context.User.Identity?.Name ?? context.Request.Headers.Host.ToString(),
                factory: partition => new FixedWindowRateLimiterOptions
                {
                    AutoReplenishment = true,
                    PermitLimit = 100,
                    Window = TimeSpan.FromMinutes(1)
                }));
    });
}
