```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();
const db = require('./database');

// Authentication middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

// Authorization check function
const canAccessUserProfile = (requestingUser, targetUserId) => {
  // Users can only access their own profile
  if (requestingUser.id === parseInt(targetUserId)) {
    return true;
  }
  // Admins can access any profile
  if (requestingUser.role === 'admin') {
    return true;
  }
  return false;
};

// SECURE: Requires authentication AND authorization
app.get('/api/users/:userId/profile', authenticateToken, async (req, res) => {
  try {
    const targetUserId = req.params.userId;

    // Authorization check: Can this user access this profile?
    if (!canAccessUserProfile(req.user, targetUserId)) {
      console.log(`Unauthorized access attempt: User ${req.user.id} tried to access user ${targetUserId}`);
      return res.status(403).json({ error: 'Access denied' });
    }

    // Only return non-sensitive fields by default
    const user = await db.query(
      'SELECT id, name, email FROM users WHERE id = $1',
      [targetUserId]
    );

    if (!user.rows[0]) {
      return res.status(404).json({ error: 'User not found' });
    }

    res.json(user.rows[0]);
  } catch (error) {
    console.error('Profile fetch error:', error.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000);
