- **Audit logging**: Logs unauthorized access attempts for security monitoring

Great question! Hierarchical authorization with role-based and relationship-based access control is a common production requirement. Here's a comprehensive pattern that handles multiple access levels with proper security controls.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');
const app = express();
const db = require('./database');

// Security headers
app.use(helmet());

// Structured security logging
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'user-profile-api' },
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Rate limiting per user
const profileLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per window
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Access level definitions
const AccessLevel = {
  NONE: 0,
  SELF: 1,
  TEAM: 2,
  DEPARTMENT: 3,
  ADMIN: 4
};

// Field visibility by access level
const fieldsByAccessLevel = {
  [AccessLevel.SELF]: ['id', 'name', 'email', 'phone', 'address', 'emergencyContact'],
  [AccessLevel.TEAM]: ['id', 'name', 'email', 'phone', 'department', 'title'],
  [AccessLevel.DEPARTMENT]: ['id', 'name', 'email', 'department', 'title'],
  [AccessLevel.ADMIN]: ['id', 'name', 'email', 'phone', 'address', 'department', 'title', 'startDate', 'salary']
};

// Authentication middleware with enhanced validation
const authenticateToken = async (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    securityLogger.warn({
      event: 'auth_missing_token',
      ip: req.ip,
      path: req.path,
      timestamp: new Date().toISOString()
    });
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET, {
      algorithms: ['HS256'],
      issuer: 'user-profile-api'
    });

    // Verify user still exists and is active
    const user = await db.query(
      'SELECT id, role, department_id, is_active FROM users WHERE id = $1',
      [decoded.userId]
    );

    if (!user.rows[0] || !user.rows[0].is_active) {
      securityLogger.warn({
        event: 'auth_inactive_user',
        userId: decoded.userId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
      return res.status(403).json({ error: 'Account is inactive' });
    }

    req.user = { ...decoded, ...user.rows[0] };
    next();
  } catch (error) {
    securityLogger.warn({
      event: 'auth_invalid_token',
      error: error.message,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

// Hierarchical authorization service
class AuthorizationService {
  static async determineAccessLevel(requestingUser, targetUserId) {
    // Self access
    if (requestingUser.id === parseInt(targetUserId)) {
      return AccessLevel.SELF;
    }

    // Admin access
    if (requestingUser.role === 'admin') {
      return AccessLevel.ADMIN;
    }

    // Check if target is in requester's team (manager access)
    if (requestingUser.role === 'manager') {
      const teamCheck = await db.query(
        'SELECT 1 FROM team_members WHERE manager_id = $1 AND member_id = $2',
        [requestingUser.id, targetUserId]
      );
      if (teamCheck.rows.length > 0) {
        return AccessLevel.TEAM;
      }
    }

    // Check if target is in same department (for department heads)
    if (requestingUser.role === 'department_head') {
      const deptCheck = await db.query(
        'SELECT 1 FROM users WHERE id = $1 AND department_id = $2',
        [targetUserId, requestingUser.department_id]
      );
      if (deptCheck.rows.length > 0) {
        return AccessLevel.DEPARTMENT;
      }
    }

    return AccessLevel.NONE;
  }

  static filterFields(userData, accessLevel) {
    const allowedFields = fieldsByAccessLevel[accessLevel] || [];
    const filtered = {};

    for (const field of allowedFields) {
      if (userData.hasOwnProperty(field)) {
        filtered[field] = userData[field];
      }
    }

    return filtered;
  }
}

