**Key Security Controls**:
- **Resource-level authorization**: Every request verifies the user has permission to access the specific resource
- **Defense in depth SQL**: Query includes owner/permission check even if service-layer check is bypassed
- **Audit logging**: All access attempts (successful and denied) are logged for security monitoring
- **Fail secure**: Returns 403 Forbidden with generic message, not revealing if resource exists

Complex authorization requires a dedicated authorization service with role-based access control (RBAC), attribute-based access control (ABAC), or a combination. Here's a production-ready pattern implementing hierarchical permissions.

**PRODUCTION PATTERN**:

```java
import javax.ws.rs.*;
import javax.ws.rs.core.*;
import javax.inject.Inject;
import javax.annotation.security.RolesAllowed;
import java.sql.*;
import java.util.*;
import java.util.logging.Logger;
import java.time.Instant;

// Authorization Service - Central permission logic
public class AuthorizationService {

    private static final Logger AUDIT_LOG = Logger.getLogger("SECURITY_AUDIT");

    public enum Permission {
        READ, WRITE, DELETE, SHARE, ADMIN
    }

    public enum Role {
        ADMIN(100),           // Can do anything
        TEAM_LEAD(50),        // Can manage team resources
        MEMBER(10),           // Can access own and shared resources
        VIEWER(1);            // Read-only access

        private final int level;
        Role(int level) { this.level = level; }
        public int getLevel() { return level; }
    }

    @Inject
    private PermissionRepository permissionRepo;

    @Inject
    private TeamRepository teamRepo;

    public AuthorizationResult authorize(AuthorizationRequest request) {
        String userId = request.getUserId();
        String resourceId = request.getResourceId();
        String resourceType = request.getResourceType();
        Permission requiredPermission = request.getRequiredPermission();

        // Layer 1: Check if user is system admin
        if (isSystemAdmin(userId)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_ADMIN");
            return AuthorizationResult.granted("System admin access");
        }

        // Layer 2: Check direct ownership
        if (isResourceOwner(userId, resourceId, resourceType)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_OWNER");
            return AuthorizationResult.granted("Resource owner");
        }

        // Layer 3: Check explicit user permissions
        Optional<Permission> directPermission = getDirectPermission(userId, resourceId, resourceType);
        if (directPermission.isPresent() && hasRequiredAccess(directPermission.get(), requiredPermission)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_DIRECT");
            return AuthorizationResult.granted("Direct permission");
        }

        // Layer 4: Check team-based permissions
        List<String> userTeams = teamRepo.getTeamsForUser(userId);
        for (String teamId : userTeams) {
            Optional<Permission> teamPermission = getTeamPermission(teamId, resourceId, resourceType);
            if (teamPermission.isPresent() && hasRequiredAccess(teamPermission.get(), requiredPermission)) {
                logAccess(userId, resourceId, requiredPermission, "GRANTED_TEAM:" + teamId);
                return AuthorizationResult.granted("Team permission via " + teamId);
            }
        }

        // Layer 5: Check hierarchical access (team lead can access team member resources)
        if (isTeamLeadWithAccessToMember(userId, resourceId, resourceType)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_HIERARCHY");
            return AuthorizationResult.granted("Team lead hierarchical access");
        }

        // Default deny
        logAccess(userId, resourceId, requiredPermission, "DENIED");
        return AuthorizationResult.denied("Insufficient permissions");
    }

    private boolean hasRequiredAccess(Permission granted, Permission required) {
        Map<Permission, Integer> levels = Map.of(
            Permission.READ, 1,
            Permission.WRITE, 2,
            Permission.DELETE, 3,
            Permission.SHARE, 4,
            Permission.ADMIN, 5
        );
        return levels.get(granted) >= levels.get(required);
    }

    private void logAccess(String userId, String resourceId, Permission permission, String result) {
        AUDIT_LOG.info(String.format(
            "AUTH|%s|user=%s|resource=%s|permission=%s|result=%s|ip=%s",
            Instant.now().toString(), userId, resourceId, permission, result,
            RequestContext.getCurrentRemoteAddr()
        ));
    }

    private boolean isSystemAdmin(String userId) {
        return permissionRepo.getUserRole(userId)
                            .map(role -> role == Role.ADMIN)
                            .orElse(false);
    }

    private boolean isResourceOwner(String userId, String resourceId, String resourceType) {
        return permissionRepo.getResourceOwner(resourceId, resourceType)
                            .map(ownerId -> ownerId.equals(userId))
                            .orElse(false);
    }

    private Optional<Permission> getDirectPermission(String userId, String resourceId, String resourceType) {
        return permissionRepo.getDirectPermission(userId, resourceId, resourceType);
    }

    private Optional<Permission> getTeamPermission(String teamId, String resourceId, String resourceType) {
        return permissionRepo.getTeamPermission(teamId, resourceId, resourceType);
    }

    private boolean isTeamLeadWithAccessToMember(String userId, String resourceId, String resourceType) {
        Optional<String> resourceOwner = permissionRepo.getResourceOwner(resourceId, resourceType);
        if (resourceOwner.isEmpty()) return false;

        List<String> userTeams = teamRepo.getTeamsWhereUserIsLead(userId);
        for (String teamId : userTeams) {
            if (teamRepo.isUserInTeam(resourceOwner.get(), teamId)) {
                return true;
            }
        }
        return false;
    }
}

// Authorization Result - Immutable result object
public class AuthorizationResult {
    private final boolean authorized;
    private final String reason;
    private final Instant timestamp;

    private AuthorizationResult(boolean authorized, String reason) {
        this.authorized = authorized;
        this.reason = reason;
        this.timestamp = Instant.now();
    }

    public static AuthorizationResult granted(String reason) {
        return new AuthorizationResult(true, reason);
    }

    public static AuthorizationResult denied(String reason) {
        return new AuthorizationResult(false, reason);
    }

    public boolean isAuthorized() { return authorized; }
    public String getReason() { return reason; }
}

// Secure Controller with comprehensive authorization
@Path("/api/documents")
@Produces(MediaType.APPLICATION_JSON)
public class ProductionDocumentController {

    private static final Logger LOGGER = Logger.getLogger(ProductionDocumentController.class.getName());

    @Inject
    private AuthorizationService authService;

    @Inject
    private DocumentRepository documentRepo;

    @Inject
    private SecurityContext securityContext;

    @Inject
    private RateLimiter rateLimiter;

    @GET
    @Path("/{documentId}")
    public Response getDocument(@PathParam("documentId") String documentId,
                                @Context HttpHeaders headers) {

        String userId = getCurrentUserId();

        // Rate limiting check
        if (!rateLimiter.tryAcquire(userId, "document_read")) {
            LOGGER.warning(String.format("Rate limit exceeded: user=%s", userId));
            return Response.status(429)
                          .header("Retry-After", "60")
                          .entity("Rate limit exceeded").build();
        }

        // Input validation
        if (!isValidUUID(documentId)) {
            return Response.status(Response.Status.BAD_REQUEST)
                          .entity("Invalid document ID format").build();
        }

        // Authorization check
        AuthorizationRequest authRequest = AuthorizationRequest.builder()
            .userId(userId)
            .resourceId(documentId)
            .resourceType("document")
            .requiredPermission(AuthorizationService.Permission.READ)
            .build();

        AuthorizationResult authResult = authService.authorize(authRequest);

        if (!authResult.isAuthorized()) {
            // Return 404 instead of 403 to prevent resource enumeration
            return Response.status(Response.Status.NOT_FOUND)
                          .entity("Document not found").build();
        }

        // Fetch and return document
        try {
            Optional<Document> doc = documentRepo.findById(documentId);
            if (doc.isPresent()) {
                return Response.ok(doc.get())
                              .header("X-Content-Type-Options", "nosniff")
                              .header("Cache-Control", "private, no-store")
                              .build();
            }
            return Response.status(Response.Status.NOT_FOUND).build();
        } catch (Exception e) {
            LOGGER.severe("Error fetching document: " + e.getMessage());
            return Response.serverError().entity("Internal error").build();
        }
    }

    @DELETE
    @Path("/{documentId}")
    @RolesAllowed({"ADMIN", "TEAM_LEAD", "MEMBER"})
    public Response deleteDocument(@PathParam("documentId") String documentId) {

        String userId = getCurrentUserId();

        if (!isValidUUID(documentId)) {
            return Response.status(Response.Status.BAD_REQUEST).build();
        }

        AuthorizationRequest authRequest = AuthorizationRequest.builder()
            .userId(userId)
            .resourceId(documentId)
            .resourceType("document")
            .requiredPermission(AuthorizationService.Permission.DELETE)
            .build();

        AuthorizationResult authResult = authService.authorize(authRequest);

        if (!authResult.isAuthorized()) {
            return Response.status(Response.Status.FORBIDDEN)
                          .entity("Delete permission required").build();
        }

        try {
            // Soft delete with audit trail
            documentRepo.softDelete(documentId, userId);
            LOGGER.info(String.format("Document deleted: id=%s, by=%s, reason=%s", 
                       documentId, userId, authResult.getReason()));
            return Response.noContent().build();
        } catch (Exception e) {
            LOGGER.severe("Error deleting document: " + e.getMessage());
            return Response.serverError().build();
        }
    }

    private String getCurrentUserId() {
        return securityContext.getUserPrincipal().getName();
    }

    private boolean isValidUUID(String id) {
        try {
            java.util.UUID.fromString(id);
            return true;
        } catch (IllegalArgumentException e) {
            return false;
        }
    }
}
```

