}

// Authorization check: users can only access their own profile, admins can access all
func canAccessUserProfile(session *Session, targetUserID int) bool {
	if session.Role == "admin" {
		return true
	}
	return session.UserID == targetUserID
}

// Filter sensitive fields based on role
func filterUserFields(session *Session, user User) User {
	if session.Role != "admin" && session.UserID != user.ID {
		user.SSN = ""
		user.Address = ""
	}
	return user
}
```

**Key Security Controls**:
- **Explicit authorization check**: `canAccessUserProfile()` verifies the requesting user owns the resource or has admin privileges
- **Consistent error responses**: Returns 404 for unauthorized access to prevent ID enumeration attacks
- **Audit logging**: Logs all access attempts and authorization failures for security monitoring
- **Field-level filtering**: Sensitive data (SSN, address) filtered based on access level

Excellent question! Complex hierarchical authorization requires a robust, centralized authorization service. Let me show you a production-ready pattern using attribute-based access control (ABAC) with caching and proper audit trails.

**PRODUCTION PATTERN**:

```go
package authorization

import (
	"context"
	"database/sql"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"sync"
	"time"

	"github.com/gorilla/mux"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/redis/go-redis/v9"
)

// Authorization decision
type AuthzDecision struct {
	Allowed    bool
	Reason     string
	FilteredFields []string
}

// Resource types for authorization
type Resource struct {
	Type string
	ID   int
}

// Action types
type Action string

const (
	ActionRead   Action = "read"
	ActionWrite  Action = "write"
	ActionDelete Action = "delete"
	ActionAdmin  Action = "admin"
)

// Authorization context with all relevant attributes
type AuthzContext struct {
	SubjectID     int
	SubjectRole   string
	SubjectTeamID int
	SubjectOrgID  int
	Resource      Resource
	Action        Action
	ClientIP      string
	Timestamp     time.Time
}

// Centralized Authorization Service
type AuthorizationService struct {
	db           *sql.DB
	redis        *redis.Client
	policyEngine *PolicyEngine
	auditLogger  *AuditLogger
	metrics      *AuthzMetrics
	cacheTTL     time.Duration
	mu           sync.RWMutex
}

// Prometheus metrics for monitoring
type AuthzMetrics struct {
	AuthzRequests    *prometheus.CounterVec
	AuthzLatency     *prometheus.HistogramVec
	AuthzDenials     *prometheus.CounterVec
	CacheHits        prometheus.Counter
	CacheMisses      prometheus.Counter
}

func NewAuthorizationService(db *sql.DB, redis *redis.Client) *AuthorizationService {
	return &AuthorizationService{
		db:           db,
		redis:        redis,
		policyEngine: NewPolicyEngine(),
		auditLogger:  NewAuditLogger(),
		metrics:      initMetrics(),
		cacheTTL:     5 * time.Minute,
	}
}

// Main authorization check - called before any resource access
func (as *AuthorizationService) Authorize(ctx context.Context, authzCtx AuthzContext) (*AuthzDecision, error) {
	start := time.Now()
	defer func() {
		as.metrics.AuthzLatency.WithLabelValues(string(authzCtx.Action)).Observe(time.Since(start).Seconds())
	}()

	as.metrics.AuthzRequests.WithLabelValues(string(authzCtx.Action), authzCtx.Resource.Type).Inc()

	// Step 1: Check cache for recent identical decisions
	cacheKey := as.buildCacheKey(authzCtx)
	if decision, err := as.checkCache(ctx, cacheKey); err == nil {
		as.metrics.CacheHits.Inc()
		return decision, nil
	}
	as.metrics.CacheMisses.Inc()

	// Step 2: Evaluate policies
	decision, err := as.evaluatePolicies(ctx, authzCtx)
	if err != nil {
		as.auditLogger.LogError(authzCtx, err)
		return &AuthzDecision{Allowed: false, Reason: "authorization_error"}, err
	}

	// Step 3: Cache the decision
	as.cacheDecision(ctx, cacheKey, decision)

	// Step 4: Audit log the decision
	as.auditLogger.LogDecision(authzCtx, decision)

	// Step 5: Emit metrics for denials
	if !decision.Allowed {
		as.metrics.AuthzDenials.WithLabelValues(string(authzCtx.Action), decision.Reason).Inc()
	}

	return decision, nil
}

// Policy evaluation with hierarchical rules
func (as *AuthorizationService) evaluatePolicies(ctx context.Context, authzCtx AuthzContext) (*AuthzDecision, error) {
	// Rule 1: Admins can access everything
	if authzCtx.SubjectRole == "admin" {
		return &AuthzDecision{
			Allowed: true,
			Reason:  "admin_access",
		}, nil
	}

	// Rule 2: Users can always access their own resources
	if authzCtx.Resource.Type == "user" && authzCtx.SubjectID == authzCtx.Resource.ID {
		return &AuthzDecision{
			Allowed: true,
			Reason:  "owner_access",
		}, nil
	}

	// Rule 3: Check team membership for user resources
	if authzCtx.Resource.Type == "user" {
		isTeammate, err := as.checkTeamMembership(ctx, authzCtx.SubjectID, authzCtx.Resource.ID)
		if err != nil {
			return nil, fmt.Errorf("team check failed: %w", err)
		}
		if isTeammate {
			return &AuthzDecision{
				Allowed:        true,
				Reason:         "team_member_access",
				FilteredFields: []string{"ssn", "salary", "personal_notes"},
			}, nil
		}
	}

	// Rule 4: Check manager-report relationship
	if authzCtx.Resource.Type == "user" {
		isManager, err := as.checkManagerRelationship(ctx, authzCtx.SubjectID, authzCtx.Resource.ID)
		if err != nil {
			return nil, fmt.Errorf("manager check failed: %w", err)
		}
		if isManager {
			return &AuthzDecision{
				Allowed:        true,
				Reason:         "manager_access",
				FilteredFields: []string{"ssn", "personal_notes"},
			}, nil
		}
	}

	// Default deny
	return &AuthzDecision{
		Allowed: false,
		Reason:  "no_matching_policy",
	}, nil
}

func (as *AuthorizationService) checkTeamMembership(ctx context.Context, subjectID, targetID int) (bool, error) {
	var sameTeam bool
	err := as.db.QueryRowContext(ctx, `
		SELECT EXISTS(
			SELECT 1 FROM team_members tm1
			JOIN team_members tm2 ON tm1.team_id = tm2.team_id
			WHERE tm1.user_id = $1 AND tm2.user_id = $2
			AND tm1.active = true AND tm2.active = true
		)`, subjectID, targetID).Scan(&sameTeam)
	return sameTeam, err
}

func (as *AuthorizationService) checkManagerRelationship(ctx context.Context, managerID, reportID int) (bool, error) {
	var isManager bool
	// Check direct and transitive (skip-level) reporting
	err := as.db.QueryRowContext(ctx, `
		WITH RECURSIVE report_chain AS (
			SELECT user_id, manager_id, 1 as depth
			FROM users WHERE manager_id = $1
			UNION ALL
			SELECT u.user_id, u.manager_id, rc.depth + 1
			FROM users u
			JOIN report_chain rc ON u.manager_id = rc.user_id
			WHERE rc.depth < 5
		)
		SELECT EXISTS(SELECT 1 FROM report_chain WHERE user_id = $2)`,
		managerID, reportID).Scan(&isManager)
	return isManager, err
}

// HTTP middleware for authorization
func (as *AuthorizationService) AuthzMiddleware(resourceType string, action Action) mux.MiddlewareFunc {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			session, ok := r.Context().Value("session").(*Session)
			if !ok {
				http.Error(w, "Unauthorized", http.StatusUnauthorized)
				return
			}

			vars := mux.Vars(r)
			resourceID, err := strconv.Atoi(vars["id"])
			if err != nil {
				http.Error(w, "Invalid resource ID", http.StatusBadRequest)
				return
			}

			authzCtx := AuthzContext{
				SubjectID:     session.UserID,
				SubjectRole:   session.Role,
				SubjectTeamID: session.TeamID,
				SubjectOrgID:  session.OrgID,
				Resource:      Resource{Type: resourceType, ID: resourceID},
				Action:        action,
				ClientIP:      r.RemoteAddr,
				Timestamp:     time.Now(),
			}

			decision, err := as.Authorize(r.Context(), authzCtx)
			if err != nil {
				log.Printf("AUTHZ_ERROR: %v", err)
				http.Error(w, "Internal Server Error", http.StatusInternalServerError)
				return
			}

			if !decision.Allowed {
				// Return 404 to prevent enumeration
				http.Error(w, "Not Found", http.StatusNotFound)
				return
			}

			// Pass filtered fields to handler
			ctx := context.WithValue(r.Context(), "authz_decision", decision)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// Audit logger for compliance
type AuditLogger struct {
	db *sql.DB
}

func (al *AuditLogger) LogDecision(authzCtx AuthzContext, decision *AuthzDecision) {
	_, err := al.db.Exec(`
		INSERT INTO authorization_audit_log 
		(subject_id, resource_type, resource_id, action, allowed, reason, client_ip, timestamp)
		VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
		authzCtx.SubjectID, authzCtx.Resource.Type, authzCtx.Resource.ID,
		authzCtx.Action, decision.Allowed, decision.Reason,
		authzCtx.ClientIP, authzCtx.Timestamp)
	if err != nil {
		log.Printf("AUDIT_LOG_ERROR: failed to log authorization decision: %v", err)
	}
}

// Usage in main application
func SetupRoutes(router *mux.Router, authzService *AuthorizationService) {
	// Apply authorization middleware to protected routes
	router.Handle("/api/users/{id}",
		authzService.AuthzMiddleware("user", ActionRead)(http.HandlerFunc(GetUserHandler)),
	).Methods("GET")

	router.Handle("/api/users/{id}",
		authzService.AuthzMiddleware("user", ActionWrite)(http.HandlerFunc(UpdateUserHandler)),
	).Methods("PUT")

	router.Handle("/api/users/{id}",
		authzService.AuthzMiddleware("user", ActionDelete)(http.HandlerFunc(DeleteUserHandler)),
	).Methods("DELETE")
}
```

**Defense in Depth Layers**:

1. **Centralized Authorization Service**: All authorization decisions go through a single service, ensuring consistent policy enforcement:
```go
// Every endpoint uses the same authorization check
decision, err := authzService.Authorize(ctx, authzContext)
```

2. **Caching with TTL**: Prevents performance issues while ensuring policy changes propagate:
```go
// Redis caching with 5-minute TTL
func (as *AuthorizationService) cacheDecision(ctx context.Context, key string, decision *AuthzDecision) {
	data, _ := json.Marshal(decision)
	as.redis.Set(ctx, key, data, as.cacheTTL)
}
```

3. **Comprehensive Audit Trail**: Every access attempt is logged for compliance and incident response:
```go
// Immutable audit log for SOC2/GDPR compliance
INSERT INTO authorization_audit_log (subject_id, resource_type, resource_id, action, allowed, reason, client_ip, timestamp)
```

**Additional Protections**:
- **Field-level filtering**: Even authorized users only see fields appropriate to their access level
- **Prometheus metrics**: Real-time monitoring of authorization failures for anomaly detection
- **Consistent error responses**: Always return 404 to prevent resource enumeration
- **Recursive relationship checking**: Handles complex org hierarchies (skip-level managers)
- **Context propagation**: Authorization decisions flow through request context for downstream handlers
- **Rate limiting**: Should be applied at the API gateway level to prevent brute-force enumeration
- **Policy versioning**: Store policy versions in audit log for compliance audits
